mapper.select:
SELECT id, user_id AS userId, name, phone, province, city, district,
       detail, is_default AS isDefault, create_time AS createTime
FROM t_address WHERE id = #{id}

mapper.update:
UPDATE t_address
SET name = #{name}, phone = #{phone}, province = #{province}, city = #{city},
    district = #{district}, detail = #{detail}, is_default = #{isDefault}
WHERE id = #{id}
